from itertools import permutations
class Solution:
    def minimumXORSum(self, nums1, nums2):
        best = None
        for perm in permutations(nums2):
            s = sum(a ^ b for a, b in zip(nums1, perm))
            if best is None or s < best:
                best = s
        return best

