class Solution:
    def minimumXORSum(self, nums1, nums2):
        n = len(nums1)
        INF = float('inf')
        dp = [INF] * (1 << n)
        dp[0] = 0
        for mask in range(1 << n):
            if dp[mask] == INF:
                continue
            i = bin(mask).count('1')
            if i >= n:
                continue
            for j in range(n):
                if not (mask & (1 << j)):
                    nm = mask | (1 << j)
                    cost = dp[mask] + (nums1[i] ^ nums2[j])
                    if cost < dp[nm]:
                        dp[nm] = cost
        return dp[(1 << n) - 1]

