var minimumXORSum = function(nums1, nums2) {
    const n = nums1.length;
    const INF = Infinity;
    const dp = new Array(1 << n).fill(INF);
    dp[0] = 0;
    for (let mask = 0; mask < (1 << n); mask++) {
        if (dp[mask] === INF) continue;
        let i = 0, t = mask;
        while (t) { i += t & 1; t >>= 1; }
        if (i >= n) continue;
        for (let j = 0; j < n; j++) {
            if (!(mask & (1 << j))) {
                const nm = mask | (1 << j);
                const cost = dp[mask] + (nums1[i] ^ nums2[j]);
                if (cost < dp[nm]) dp[nm] = cost;
            }
        }
    }
    return dp[(1 << n) - 1];
};
